    &quot;code&quot;: &quot;import { useState } from &#39;react&#39;;
import &#39;./styles.css&#39;; // We&#39;ll create this basic CSS file

const SIZE = 4;

// --- Utility Functions (from the original problem) ---
function getEmptyBoard() {
  return Array(SIZE).fill(null).map(() =&gt; Array(SIZE).fill(0));
}

function getRandomInt(max) {
  return Math.floor(Math.random() * max);
}

// Important: This function mutates the board it receives
function addRandomTile(board) {
  const emptyTiles = [];
  for (let r = 0; r &lt; SIZE; r++) {
    for (let c = 0; c &lt; SIZE; c++) {
      if (board[r][c] === 0) emptyTiles.push([r, c]);
    }
  }
  if (emptyTiles.length === 0) return board; // No space to add
  const [r, c] = emptyTiles[getRandomInt(emptyTiles.length)];
  board[r][c] = Math.random() &lt; 0.9 ? 2 : 4;
  return board;
}

// This function returns a new board without mutating the original
function compress(board) {
  let newBoard = board.map(row =&gt; {
    let newRow = row.filter(val =&gt; val !== 0); // Get non-zero numbers
    while (newRow.length &lt; SIZE) newRow.push(0); // Pad with zeros
    return newRow;
  });
  return newBoard;
}

// Important: This function mutates the board it receives
function merge(board) {
  for (let r = 0; r &lt; SIZE; r++) {
    for (let c = 0; c &lt; SIZE - 1; c++) {
      if (board[r][c] !== 0 &amp;&amp; board[r][c] === board[r][c + 1]) {
        board[r][c] *= 2;
        board[r][c + 1] = 0;
        // Note: In a full game, you might only merge once per tile.
        // This simple version can cause cascading merges like 2-2-4 -&gt; 4-0-4 -&gt; 8-0-0 if compress is not run in between.
        // For this exercise&#39;s \&quot;merge only\&quot; button, this behavior is fine.
      }
    }
  }
  return board;
}

// --- React Component ---
function App() {
  const [board, setBoard] = useState(getEmptyBoard());

  const handleAddRandom = () =&gt; {
    // Create a copy of the board to avoid direct state mutation
    const boardCopy = board.map(row =&gt; [...row]);
    const newBoardWithTile = addRandomTile(boardCopy);
    setBoard(newBoardWithTile);
  };

  const handleCompress = () =&gt; {
    // compress function returns a new board, so no copy needed before calling
    const compressedBoard = compress(board);
    setBoard(compressedBoard);
  };

  const handleMerge = () =&gt; {
    // Create a copy of the board as merge function mutates it
    const boardCopy = board.map(row =&gt; [...row]);
    const mergedBoard = merge(boardCopy);
    setBoard(mergedBoard);
  };

  const handleReset = () =&gt; {
    setBoard(getEmptyBoard());
  }

  return (
    &lt;div className=\&quot;container\&quot;&gt;
      &lt;h1&gt;2048 Mechanics Explorer&lt;/h1&gt;
      &lt;div className=\&quot;board\&quot;&gt;
        {board.map((row, rowIndex) =&gt; (
          &lt;div key={rowIndex} className=\&quot;row\&quot;&gt;
            {row.map((cell, cellIndex) =&gt; (
              &lt;div key={cellIndex} className={`cell cell-${cell}`}&gt;
                {cell !== 0 ? cell : &#39;&#39;}
              &lt;/div&gt;
            ))}
          &lt;/div&gt;
        ))}
      &lt;/div&gt;
      &lt;div className=\&quot;controls\&quot;&gt;
        &lt;button onClick={handleAddRandom}&gt;Add Random Tile&lt;/button&gt;
        &lt;button onClick={handleCompress}&gt;Compress Left&lt;/button&gt;
        &lt;button onClick={handleMerge}&gt;Merge Left&lt;/button&gt;
        &lt;button onClick={handleReset} className=\&quot;restart\&quot;&gt;Reset Board&lt;/button&gt;
      &lt;/div&gt;
    &lt;/div&gt;
  );
}

export default App;&quot;
